const input = $input.first().json;

const sessionId = input.numero || input.sessionId || input.chatInput || 'unknown';
const chatInput = input.mensaje || input.chatInput || '';
const contexto = input.contexto || '';

return [{ json: { chatInput, sessionId, contexto, numero: sessionId } }];

const redisValue = $input.first().json.value || 'ninguno';
const sesion = $('Leer Sesion Activa').item.json;

return [{
  json: {
    chatInput: sesion.chatInput,
    sessionId: sesion.sessionId,
    contexto: sesion.contexto,
    activeAgent: redisValue
  }
}];

const departamento = $input.first().json.text.trim();
const sessionId = $('Leer Sesion Activa').item.json.sessionId;

